import{_ as e,o,c as a,ag as n}from"./chunks/framework.1N8rnUr9.js";const g=JSON.parse('{"title":"Account Connection","description":"","frontmatter":{},"headers":[],"relativePath":"features/connection.md","filePath":"features/connection.md","lastUpdated":1775715475000}'),r={name:"features/connection.md"};function i(s,t,l,u,d,c){return o(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="account-connection" tabindex="-1">Account Connection <a class="header-anchor" href="#account-connection" aria-label="Permalink to &quot;Account Connection&quot;">​</a></h1><p>TubeBay supports a dual-mode authentication architecture to ensure compatibility with all types of users and environments. Whether you want a &quot;one-click&quot; experience or full control over your API keys, TubeBay has you covered.</p><h2 id="google-oauth-2-0-proxy-mode" tabindex="-1">Google OAuth 2.0 (Proxy Mode) <a class="header-anchor" href="#google-oauth-2-0-proxy-mode" aria-label="Permalink to &quot;Google OAuth 2.0 (Proxy Mode)&quot;">​</a></h2><p>OAuth is the gold standard for secure, limited-access authentication. TubeBay uses a secure authentication proxy to facilitate this connection.</p><h3 id="how-it-works" tabindex="-1">How it works: <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works:&quot;">​</a></h3><ol><li><strong>Request:</strong> The plugin requests an authorization code from the TubeBay Auth Proxy.</li><li><strong>Consent:</strong> You authorize the TubeBay application to &quot;View your YouTube account&quot; on Google&#39;s secure consent screen.</li><li><strong>Exchange:</strong> Google sends an authorization code back to the proxy, which then provides you with a <strong>Refresh Token</strong>.</li><li><strong>Storage:</strong> Only the Refresh Token is stored on your WordPress site.</li></ol><h3 id="advantages" tabindex="-1">Advantages: <a class="header-anchor" href="#advantages" aria-label="Permalink to &quot;Advantages:&quot;">​</a></h3><ul><li><strong>No Project Hassle:</strong> You don&#39;t need to create a Google Cloud project or manage API quotas.</li><li><strong>Revocable:</strong> You can disconnect the plugin at any time from your Google account dashboard.</li><li><strong>Secure:</strong> Your permanent Google credentials are never shared with your website.</li></ul><h2 id="manual-api-key-mode" tabindex="-1">Manual API Key Mode <a class="header-anchor" href="#manual-api-key-mode" aria-label="Permalink to &quot;Manual API Key Mode&quot;">​</a></h2><p>For power users or those who wish to maintain their own API quotas and Google Cloud projects, TubeBay allows for manual credential entry.</p><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li><strong>Google Cloud Project:</strong> You must have an active project.</li><li><strong>YouTube Data API v3:</strong> This specific API must be enabled.</li><li><strong>API Key:</strong> A standard unrestricted or IP-restricted API key.</li><li><strong>Channel ID:</strong> The unique ID of the YouTube channel you wish to sync.</li></ul><h3 id="comparison-table" tabindex="-1">Comparison Table <a class="header-anchor" href="#comparison-table" aria-label="Permalink to &quot;Comparison Table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Google OAuth</th><th>Manual API</th></tr></thead><tbody><tr><td>Ease of Setup</td><td>High</td><td>Moderate</td></tr><tr><td>Security</td><td>Excellent</td><td>Good</td></tr><tr><td>Project Required</td><td>No</td><td>Yes</td></tr><tr><td>Custom Quotas</td><td>No</td><td>Yes</td></tr><tr><td>Stability</td><td>High</td><td>High</td></tr></tbody></table><h2 id="connection-status-discovery" tabindex="-1">Connection Status &amp; Discovery <a class="header-anchor" href="#connection-status-discovery" aria-label="Permalink to &quot;Connection Status &amp; Discovery&quot;">​</a></h2><p>When you connect via either method, TubeBay automatically attempts to:</p><ol><li><strong>Validate Credentials:</strong> Ensure the token or key is valid.</li><li><strong>Discover Metadata:</strong> Pull the Channel Name, Description, and Thumbnail to personalize your dashboard.</li><li><strong>Establish Sync:</strong> Create the initial mapping between your site and YouTube.</li></ol>',17)])])}const p=e(r,[["render",i]]);export{g as __pageData,p as default};
